query:
-- Step 1: Find all test user IDs
SET @test_user_ids = (SELECT GROUP_CONCAT(id) FROM users WHERE name LIKE 'Test%');

-- Step 2: Find all test novel IDs
SET @test_novel_ids = (SELECT GROUP_CONCAT(id) FROM novels WHERE title LIKE 'Test%');

-- Step 3: Find all test order IDs (from test users)
SET @test_order_ids = (SELECT GROUP_CONCAT(id) FROM orders WHERE userId IN (SELECT id FROM users WHERE name LIKE 'Test%'));

-- Delete coupon usages for test orders
DELETE cu FROM couponUsages cu
INNER JOIN orders o ON cu.orderId = o.id
INNER JOIN users u ON o.userId = u.id
WHERE u.name LIKE 'Test%';

-- Delete order history for test orders
DELETE oh FROM orderHistory oh
INNER JOIN orders o ON oh.orderId = o.id
INNER JOIN users u ON o.userId = u.id
WHERE u.name LIKE 'Test%';

-- Delete payments for test orders
DELETE p FROM payments p
INNER JOIN orders o ON p.orderId = o.id
INNER JOIN users u ON o.userId = u.id
WHERE u.name LIKE 'Test%';

-- Delete purchases for test users
DELETE FROM purchases WHERE userId IN (SELECT id FROM users WHERE name LIKE 'Test%');

-- Delete order items for test orders
DELETE oi FROM orderItems oi
INNER JOIN orders o ON oi.orderId = o.id
INNER JOIN users u ON o.userId = u.id
WHERE u.name LIKE 'Test%';

-- Delete orders for test users
DELETE FROM orders WHERE userId IN (SELECT id FROM users WHERE name LIKE 'Test%');

-- Delete cart items for test users
DELETE ci FROM cartItems ci
INNER JOIN carts c ON ci.cartId = c.id
INNER JOIN users u ON c.userId = u.id
WHERE u.name LIKE 'Test%';

-- Delete carts for test users
DELETE FROM carts WHERE userId IN (SELECT id FROM users WHERE name LIKE 'Test%');

-- Delete point transactions for test users
DELETE FROM pointTransactions WHERE userId IN (SELECT id FROM users WHERE name LIKE 'Test%');

-- Delete test episodes
DELETE FROM episodes WHERE novelId IN (SELECT id FROM novels WHERE title LIKE 'Test%');

-- Delete test novels
DELETE FROM novels WHERE title LIKE 'Test%';

-- Delete test coupons
DELETE FROM coupons WHERE code LIKE 'TEST%' OR code LIKE 'test%';

-- Delete test users
DELETE FROM users WHERE name LIKE 'Test%';

SELECT 'Test data cleaned successfully' AS result;

